1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const countNeighbors = (grid: Grid, row: number, col: number): number => {
5	  let count = 0;
6	  for (let r = row - 1; r <= row + 1; r++) {
7	    for (let c = col - 1; c <= col + 1; c++) {
8	      if (r === row && c === col) continue;
9	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[0].length && grid[r][c]) {
10	        count++;
11	      }
12	    }
13	  }
14	  return count;
15	};
16	
17	const willSurviveToNextGeneration = (isAlive: boolean, neighbors: number): boolean => {
18	  if (isAlive && neighbors < 2) {
19	    return false; // Underpopulation rule
20	  }
21	  if (isAlive && (neighbors === 2 || neighbors === 3)) {
22	    return true; // Survival rule
23	  }
24	  if (!isAlive && neighbors === 3) {
25	    return true; // Reproduction rule
26	  }
27	  return isAlive; // Default: cell stays as is
28	};
29	
30	export function nextGeneration(grid: Grid): Grid {
31	  if (grid.length === 0) {
32	    return [];
33	  }
34	
35	  return grid.map((row, rowIdx) =>
36	    row.map((cell, colIdx) => {
37	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
38	      return willSurviveToNextGeneration(cell, neighbors);
39	    })
40	  );
41	}
